/**
 * Notyf Lite
 * Minimal implementation for Next Design
 */
(function (global, factory) {
  typeof exports === 'object' && typeof module !== 'undefined' ? module.exports = factory() :
  typeof define === 'function' && define.amd ? define(factory) :
  (global = typeof globalThis !== 'undefined' ? globalThis : global || self, global.Notyf = factory());
})(this, (function () { 'use strict';
  const Notyf = function(options) {
    this.options = options || {};
    
    const toast = (title, icon) => {
      if (window.Swal) {
        Swal.fire({
          toast: true,
          position: 'top-end',
          showConfirmButton: false,
          timer: 3000,
          timerProgressBar: true,
          icon: icon,
          title: title,
          didOpen: (t) => {
            t.addEventListener('mouseenter', Swal.stopTimer);
            t.addEventListener('mouseleave', Swal.resumeTimer);
          }
        });
      } else {
        console.log(`Notyf ${icon}:`, title);
      }
    };

    const getMessage = (msg) => {
      if (typeof msg === 'string') return msg;
      if (typeof msg === 'object' && msg !== null) {
        return msg.message || msg.title || JSON.stringify(msg);
      }
      return String(msg);
    };

    this.success = function(msg) { toast(getMessage(msg), 'success'); };
    this.error = function(msg) { toast(getMessage(msg), 'error'); };
    this.open = function(opt) { toast(getMessage(opt), opt.type || 'info'); };
  };
  return Notyf;
}));

